    queryKey: key("transfers", userId, workspaceId),
    queryFn: listWarehouseTransfers,
    enabled: user !== null,
  })
  const mutation = useMutation({
    mutationKey: key("transfers", userId, workspaceId),
    mutationFn: recordWarehouseTransfer,
